1	import { UserNotConfirmedException } from '@aws-sdk/client-cognito-identity-provider';
2	import {
3	  BadRequestException,
4	  Injectable,
5	  InternalServerErrorException,
6	  Logger,
7	  NotFoundException,
8	  UnauthorizedException,
9	} from '@nestjs/common';
10	import { ConfigService } from '@nestjs/config';
11	import { TransactionHost } from '@nestjs-cls/transactional';
12	
13	import { UserService } from '@/modules/user';
14	import { TransactionalAdapterTypeOrm } from '@/modules/global';
15	import {
16	  MediaType,
17	  OtpEntity,
18	  OtpType,
19	  UserEntity,
20	  UserRole,
21	  UserStatus,
22	} from '@/db';
23	
24	import { CognitoService } from './cognito.service';
25	import { SocialAuthService } from './social-auth.service';
26	import { env, isDevelopment } from '@/env';
27	import { OtpService } from '@/modules/otp';
28	import { NotificationService } from '@/modules/notification';
29	
30	@Injectable()
31	export class AuthService {
32	  private readonly logger = new Logger(AuthService.name);
33	
34	  constructor(
35	    private readonly configService: ConfigService,
36	    private readonly cognitoService: CognitoService,
37	    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
38	    private readonly userService: UserService,
39	    private readonly otpService: OtpService,
40	    private readonly notificationService: NotificationService,
41	    private readonly socialAuthService: SocialAuthService,
42	  ) {}
43	
44	  async signupWithoutConfirmation(dto: {
45	    email: string;
46	    firstName: string;
47	    lastName: string;
48	    patronymic?: string | null;
49	    phone: string;
50	    roles: UserRole[];
51	  }) {
52	    const { email, firstName, lastName, patronymic, phone, roles } = dto;
53	
54	    // Send invite admin with temp password
55	    const { tempPassword } =
56	      await this.cognitoService.signupWithoutConfirmation(dto);
57	
58	    const user = await this.userService.create({
59	      email,
60	      firstName,
61	      lastName,
62	      patronymic,
63	      phone,
64	      roles,
65	      status: UserStatus.Active,
66	    });
67	
68	    await this.notificationService.sendInvite({
69	      email,
70	      firstName,
71	      lastName,
72	      patronymic,
73	      role: roles[0],
74	      tempPassword,
75	    });
76	
77	    return { user, tempPassword };
78	  }
79	
80	  async signUp(dto: {
81	    password: string;
82	    firstName: string;
83	    lastName: string;
84	    patronymic?: string | null;
85	    phoneOtpId: string;
86	    emailOtpId: string;
87	    role: UserRole;
88	  }) {
89	    const {
90	      password,
91	      firstName,
92	      lastName,
93	      patronymic,
94	      phoneOtpId,
95	      emailOtpId,
96	    } = dto;
97	
98	    this.logger.log(
99	      `[signUp] Start: emailOtpId=${emailOtpId}, phoneOtpId=${phoneOtpId}, role=${dto.role}`,
100	    );
101	
102	    const emailOtp = await this.otpService.findApproved(
103	      emailOtpId,
104	      OtpType.SignUp,
105	      MediaType.Email,
106	    );
107	
108	    this.logger.log(`[signUp] Email OTP approved for: ${emailOtp.sentTo}`);
109	
110	    const phoneOtp = await this.otpService.findApproved(
111	      phoneOtpId,
112	      OtpType.SignUp,
113	      MediaType.Phone,
114	    );
115	
116	    this.logger.log(`[signUp] Phone OTP approved for: ${phoneOtp.sentTo}`);
117	
118	    const emailExists = await this.emailExists(emailOtp.sentTo);
119	
120	    if (emailExists) {
121	      this.logger.warn(
122	        `[signUp] Rejected: email already exists — ${emailOtp.sentTo}`,
123	      );
124	      throw new BadRequestException('User with this email already exists');
125	    }
126	
127	    const phoneExists = await this.phoneExists(phoneOtp.sentTo);
128	
129	    if (phoneExists) {
130	      this.logger.warn(
131	        `[signUp] Rejected: phone already exists — ${phoneOtp.sentTo}`,
132	      );
133	      throw new BadRequestException('User with this phone already exists');
134	    }
135	
136	    try {
137	      if (!env.AWS_COGNITO_SKIP) {
138	        this.logger.log(
139	          `[signUp] Creating Cognito user for: ${emailOtp.sentTo}`,
140	        );
141	        await this.cognitoService.signUp({
142	          email: emailOtp.sentTo,
143	          firstName,
144	          lastName,
145	          patronymic,
146	          password,
147	        });
148	        this.logger.log(
149	          `[signUp] Cognito user created successfully for: ${emailOtp.sentTo}`,
150	        );
151	      }
152	
153	      this.logger.log(`[signUp] Creating DB user for: ${emailOtp.sentTo}`);
154	      await this.userService.create({
155	        email: emailOtp.sentTo,
156	        phone: phoneOtp.sentTo,
157	        firstName,
158	        lastName,
159	        patronymic,
160	        roles: [dto.role],
161	        status: UserStatus.Active,
162	      });
163	      this.logger.log(
164	        `[signUp] DB user created successfully for: ${emailOtp.sentTo}`,
165	      );
166	
167	      await this.otpService.removeOtp([emailOtpId, phoneOtpId]);
168	
169	      this.logger.log(
170	        `[signUp] Signing in after registration for: ${emailOtp.sentTo}`,
171	      );
172	      return this.signIn({
173	        email: emailOtp.sentTo,
174	        password,
175	      });
176	    } catch (error) {
177	      const errorName =
178	        error?.name ?? error?.constructor?.name ?? 'UnknownError';
179	      const errorMessage = error?.message ?? String(error);
180	      const errorCode =
181	        error?.$metadata?.httpStatusCode ?? error?.code ?? 'N/A';
182	
183	      this.logger.error(
184	        `[signUp] Failed for email=${emailOtp?.sentTo}, phone=${phoneOtp?.sentTo}: [${errorName}] (HTTP ${errorCode}) ${errorMessage}`,
185	        error?.stack,
186	      );
187	
188	      // todo: handle invalid passwords separately
189	      if (error instanceof UserNotConfirmedException) {
190	        throw new BadRequestException('Invalid password');
191	      } else {
192	        throw new InternalServerErrorException();
193	      }
194	    }
195	  }
196	
197	  async signIn(dto: { email: string; password: string }) {
198	    const result = await this.cognitoService.signIn(dto.email, dto.password);
199	
200	    const user = await this.txHost.tx.getRepository(UserEntity).findOne({
201	      where: { email: dto.email },
202	    });
203	
204	    if (!user) {
205	      await this.cognitoService.deleteUser(dto.email);
206	      throw new UnauthorizedException('Email is not registered');
207	    }
208	
209	    // Check if we got a challenge (temporary password case)
210	    if (result.ChallengeName === 'NEW_PASSWORD_REQUIRED') {
211	      return {
212	        status: 'CHALLENGE',
213	        challengeName: result.ChallengeName,
214	        session: result.Session,
215	        challengeParameters: result.ChallengeParameters,
216	        message: 'Temporary password detected. New password required.',
217	      };
218	    }
219	
220	    if (result.AuthenticationResult?.AccessToken) {
221	      return {
222	        status: 'SUCCESS',
223	        payload: {
224	          accessToken: isDevelopment()
225	            ? dto.email
226	            : result.AuthenticationResult.AccessToken,
227	          refreshToken: result.AuthenticationResult.RefreshToken,
228	          idToken: result.AuthenticationResult.IdToken,
229	        },
230	      };
231	    }
232	
233	    return {
234	      status: 'FAILED',
235	      message: 'Authentication failed',
236	    };
237	  }
238	
239	  async resendConfirmationCode(email: string) {
240	    try {
241	      await this.cognitoService.resendConfirmationCode(email);
242	      return {
243	        status: 'SUCCESS',
244	        message: 'Confirmation code resent',
245	      };
246	    } catch (error) {
247	      return {
248	        status: 'FAILED',
249	        message: error.message,
250	      };
251	    }
252	  }
253	
254	  async respondToNewPasswordChallenge(dto: {
255	    email: string;
256	    newPassword: string;
257	    session: string;
258	  }) {
259	    const { email, newPassword, session } = dto;
260	
261	    try {
262	      const result = await this.cognitoService.respondToNewPasswordChallenge(
263	        email,
264	        newPassword,
265	        session,
266	      );
267	
268	      if (result.AuthenticationResult?.AccessToken) {
269	        return {
270	          status: 'SUCCESS',
271	          payload: {
272	            accessToken: result.AuthenticationResult.AccessToken,
273	            refreshToken: result.AuthenticationResult.RefreshToken,
274	            idToken: result.AuthenticationResult.IdToken,
275	          },
276	        };
277	      }
278	
279	      return {
280	        status: 'FAILED',
281	        message: 'Authentication failed',
282	      };
283	    } catch (error) {
284	      return {
285	        status: 'FAILED',
286	        message: error.message,
287	      };
288	    }
289	  }
290	
291	  async refreshToken(payload: { refreshToken: string; accessToken: string }) {
292	    const { refreshToken, accessToken } = payload;
293	
294	    const result = await this.cognitoService.refreshToken(
295	      refreshToken,
296	      accessToken,
297	    );
298	
299	    if (result.AuthenticationResult) {
300	      return {
301	        accessToken: isDevelopment()
302	          ? accessToken
303	          : result.AuthenticationResult.AccessToken,
304	        refreshToken: refreshToken,
305	        idToken: result.AuthenticationResult.IdToken,
306	      };
307	    } else {
308	      throw new UnauthorizedException('Refresh token failed');
309	    }
310	  }
311	
312	  async signInWithGoogle(code: string) {
313	    const args = await this.cognitoService.signInWithSocial(
314	      code,
315	      `${this.configService.get<string>('CORE_PUBLIC_URL')}/auth/oauth/google/callback`,
316	    );
317	
318	    return this.signInWithSocial(args);
319	  }
320	
321	  async signInWithApple(code: string) {
322	    const args = await this.cognitoService.signInWithSocial(
323	      code,
324	      `${this.configService.get<string>('CORE_PUBLIC_URL')}/auth/oauth/apple/callback`,
325	    );
326	
327	    return this.signInWithSocial(args);
328	  }
329	
330	  private async signInWithSocial(args: {
331	    email: string;
332	    firstName?: string;
333	    lastName?: string;
334	    picture?: string | null;
335	    accessToken: string;
336	    refreshToken: string;
337	  }) {
338	    const { email, firstName, lastName, picture, accessToken, refreshToken } = args;
339	
340	    const userRepository = this.txHost.tx.getRepository(UserEntity);
341	
342	    let user = await userRepository.findOne({ where: { email } });
343	
344	    if (!user) {
345	      user = await this.userService.create({
346	        email,
347	        firstName: firstName || '',
348	        lastName: lastName || '',
349	        patronymic: null,
350	        roles: [UserRole.Seller],
351	        status: UserStatus.Active,
352	        phone: '',
353	      });
354	    }
355	
356	    if (!user.photoFileId && picture) {
357	      const file = await this.socialAuthService.uploadAvatarFromUrl(picture);
358	      if (file) {
359	        await userRepository.update(user.id, { photoFileId: file.id });
360	      }
361	    }
362	
363	    return {
364	      status: 'SUCCESS',
365	      payload: {
366	        accessToken,
367	        refreshToken,
368	      },
369	    };
370	  }
371	
372	  async signOut(accessToken: string) {
373	    if (env.AWS_COGNITO_SKIP) {
374	      return;
375	    }
376	
377	    await this.cognitoService.signOut(accessToken);
378	  }
379	
380	  async emailExists(email: string) {
381	    const user = await this.txHost.tx.getRepository(UserEntity).findOne({
382	      where: { email },
383	    });
384	
385	    return !!user;
386	  }
387	
388	  async phoneExists(phone: string) {
389	    const user = await this.txHost.tx.getRepository(UserEntity).findOne({
390	      where: { phone },
391	    });
392	
393	    return !!user;
394	  }
395	
396	  async signInWithGoogleNative(idToken: string) {
397	    const { email, firstName, lastName, picture } =
398	      await this.socialAuthService.verifyGoogleToken(idToken);
399	
400	    return this.txHost.withTransaction(async () => {
401	      const userRepo = this.txHost.tx.getRepository(UserEntity);
402	      let user = await userRepo.findOne({ where: { email } });
403	
404	      if (!user) {
405	        user = await this.userService.create({
406	          email,
407	          firstName,
408	          lastName,
409	          patronymic: null,
410	          roles: [UserRole.Seller],
411	          status: UserStatus.Active,
412	          phone: '',
413	        });
414	      }
415	
416	      if (!user.photoFileId && picture) {
417	        const file = await this.socialAuthService.uploadAvatarFromUrl(picture);
418	        if (file) {
419	          await userRepo.update(user.id, { photoFileId: file.id });
420	        }
421	      }
422	
423	      const tokens = await this.cognitoService.signInSocialUser({
424	        email,
425	        firstName,
426	        lastName,
427	      });
428	
429	      return { status: 'SUCCESS', payload: tokens };
430	    });
431	  }
432	
433	  async signInWithAppleNative(dto: {
434	    identityToken: string;
435	    firstName?: string;
436	    lastName?: string;
437	  }) {
438	    const { appleUserId, email } =
439	      await this.socialAuthService.verifyAppleToken(dto.identityToken);
440	
441	    return this.txHost.withTransaction(async () => {
442	      const userRepo = this.txHost.tx.getRepository(UserEntity);
443	
444	      let user = await userRepo.findOne({ where: { appleUserId } });
445	
446	      if (!user && email) {
447	        user = await userRepo.findOne({ where: { email } });
448	      }
449	
450	      if (!user) {
451	        if (!email) {
452	          throw new UnauthorizedException(
453	            'Email is required for first-time Apple sign-in',
454	          );
455	        }
456	
457	        user = await this.userService.create({
458	          email,
459	          firstName: dto.firstName ?? '',
460	          lastName: dto.lastName ?? '',
461	          patronymic: null,
462	          roles: [UserRole.Seller],
463	          status: UserStatus.Active,
464	          phone: '',
465	        });
466	      }
467	
468	      if (!user.appleUserId) {
469	        await userRepo.update(user.id, { appleUserId });
