23	@Controller('/')
24	export class AuthController {
25	  constructor(
26	    private readonly authService: AuthService,
27	    private readonly optService: OtpService,
28	  ) {}
29	
30	  @Post('/sign-up')
31	  async signUp(@Body() body: SignUpRequestDto) {
32	    return this.authService.signUp(body);
33	  }
34	
35	  @Post('/send-otp')
36	  async sendOtp(@Body() body: SendOtpDto) {
37	    // SIGN_UP with both email and phone: handle both channels in one call
38	    // so they share a single OTP code.
39	    if (body.email && body.phone) {
40	      return this.optService.sendOtp([
41	        { source: body.email, type: body.type, mediaType: MediaType.Email },
42	        { source: body.phone, type: body.type, mediaType: MediaType.Phone },
43	      ]);
