import { AddressDto, AddressService } from '@/modules/address';
import { TransactionalAdapterTypeOrm } from '@/modules/global';
import { WalletService } from '@/modules/payments';

@Injectable()
export class UserService {
  constructor(
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly walletService: WalletService,
    private readonly addressService: AddressService,
  ) {}

  async create(dto: {
    email: string;
    firstName: string;
    lastName: string;
    patronymic?: string | null;
    roles: UserRole[];
    phone: string;
    status: UserStatus;
  }) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.save({
      email: dto.email,
      phone: dto.phone,
      firstName: dto.firstName,
      lastName: dto.lastName,
      patronymic: dto.patronymic ?? null,
      roles: dto.roles,
      selectedRole: dto.roles[0],
      status: dto.status,
    });

    await this.walletService.create(user.id);

    return user;
  }

  async getOne(userId: string): Promise<UserEntity> {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.findOne({
      where: { id: userId },
      relations: ['admin', 'admin.adminRoles'],
    });

