    private readonly walletService: WalletService,
    private readonly addressService: AddressService,
  ) {}

  async create(dto: {
    email: string;
    firstName: string;
    lastName: string;
    patronymic?: string | null;
    roles: UserRole[];
    phone: string;
    status: UserStatus;
  }) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.save({
      email: dto.email,
      phone: dto.phone,
      firstName: dto.firstName,
      lastName: dto.lastName,
      patronymic: dto.patronymic ?? null,
      roles: dto.roles,
      selectedRole: dto.roles[0],
      status: dto.status,
    });

    await this.walletService.create(user.id);

    return user;
  }

  async getOne(userId: string): Promise<UserEntity> {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.findOne({
      where: { id: userId },
      relations: ['admin', 'admin.adminRoles'],
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    return user;
  }

  async updateOne(userId: string, dto: {
    firstName: string;
    lastName: string;
    patronymic?: string | null;
  }) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.findOne({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    return userRepository.save({
      ...user,
      firstName: dto.firstName,
      lastName: dto.lastName,
      patronymic: dto.patronymic ?? null,
    });
  }

  async updatePhoto(userId: string, photoFileId: string | null) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.findOne({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    if (photoFileId) {
      const fileRepository = this.txHost.tx.getRepository(FileEntity);
      const file = await fileRepository.findOne({ where: { id: photoFileId } });
      if (!file || file.status !== FileStatus.UPLOADED) {
        throw new BadRequestException('Invalid photo file');
      }
    }

    return userRepository.save({ ...user, photoFileId });
  }

  // Address

  async getAddress(userId: string): Promise<AddressEntity[]> {
    return this.addressService.getAll(userId);
  }

  async updateAddress(userId: string, dto: AddressDto): Promise<AddressEntity> {
    if (dto.id) {
      const addressId: string = dto.id;
      return this.addressService.upsert(addressId, { ...dto, userId });
    }

    return this.addressService.create({ ...dto, userId });
  }

  async deleteAddress(userId: string, addressId: string): Promise<void> {
    return this.addressService.delete(addressId);
  }

  // Settings
  async getSettings(userId: string) {
    const user = await this.getOne(userId);
    return {
      ...user.settings,
      CURRENCY: user.settings?.CURRENCY ?? DEFAULT_CURRENCY,
      NOTIFICATIONS: user.settings?.NOTIFICATIONS ?? {
        general: true,
        buyback: true,
        authenticator: true,
        accountSecurity: true,
      },
    };
  }

  async updateSettings(userId: string, dto: Partial<UserSettings>) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.findOne({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    return userRepository.save({
      id: userId,
      settings: {
        ...user.settings,
        ...dto,
      },
    });
  }

  getByEmail(email: string) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    return userRepository.findOne({
      where: { email },
    });
  }

  getByPhone(phone: string) {
    const userRepository = this.txHost.tx.getRepository(UserEntity);

    return userRepository.findOne({
      where: { phone },
    });
  }
}

