async refreshToken(payload: { refreshToken: string; accessToken: string }) {
  const { refreshToken, accessToken } = payload;

  // Handle our own refresh JWTs (issued for social sign-in of email+password users)
  try {
    const decoded = this.jwtService.verify<{ sub: string; type: string }>(
      refreshToken,
      { secret: env.JWT_SECRET },
    );
    if (decoded?.sub && decoded?.type === 'refresh') {
      const newAccessToken = this.jwtService.sign(
        { sub: decoded.sub, type: 'access' },
        { secret: env.JWT_SECRET, expiresIn: '1h' },
      );
      const newRefreshToken = this.jwtService.sign(
        { sub: decoded.sub, type: 'refresh' },
        { secret: env.JWT_SECRET, expiresIn: '30d' },
      );
      return { accessToken: newAccessToken, refreshToken: newRefreshToken, idToken: newAccessToken };
    }
  } catch {
    // not our JWT, fall through to Cognito
  }

  const result = await this.cognitoService.refreshToken(
    refreshToken,
    accessToken,
  );

  if (result.AuthenticationResult) {
    return {
      accessToken: isDevelopment()
        ? accessToken
        : result.AuthenticationResult.AccessToken,
      refreshToken: refreshToken,
      idToken: result.AuthenticationResult.IdToken,
    };
  } else {
    throw new UnauthorizedException('Refresh token failed');
  }
}

