async signOut(accessToken: string) {
  if (env.AWS_COGNITO_SKIP) {
    return;
  }

  // Our own JWTs (social sign-in for email+password users) are stateless — nothing to revoke in Cognito
  try {
    const decoded = this.jwtService.verify<{ type: string }>(accessToken, {
      secret: env.JWT_SECRET,
    });
    if (decoded?.type === 'access') return;
  } catch {
    // not our JWT
  }

  await this.cognitoService.signOut(accessToken);
}

async emailExists(email: string) {
  const user = await this.txHost.tx.getRepository(UserEntity).findOne({
    where: { email },
  });

  return !!user;
}

async phoneExists(phone: string) {
  const user = await this.txHost.tx.getRepository(UserEntity).findOne({
    where: { phone },
  });

  return !!user;
}

async signInWithGoogleNative(idToken: string) {
  const { email, firstName, lastName, picture } =
    await this.socialAuthService.verifyGoogleToken(idToken);

  return this.txHost.withTransaction(async () => {
    const userRepo = this.txHost.tx.getRepository(UserEntity);
    let user = await userRepo.findOne({ where: { email } });

    if (!user) {
      user = await this.userService.create({
        email,
        firstName,
        lastName,
        patronymic: null,
        roles: [UserRole.Seller],
        status: UserStatus.Active,
        phone: '',
      });
    }

    if (!user.photoFileId && picture) {
      const file = await this.socialAuthService.uploadAvatarFromUrl(picture);
      if (file) {
        await userRepo.update(user.id, { photoFileId: file.id });
      }
    }

    if (!user.linkedProviders.includes('google')) {
      await userRepo.update(user.id, {
        linkedProviders: [...user.linkedProviders, 'google'],
      });
    }

    // For users who registered via email+password, don't overwrite their Cognito password.
    // Issue our own JWT so both sign-in methods remain functional.
    if (user.hasEmailPassword) {
      return { status: 'SUCCESS', payload: this.issueOwnTokens(email) };
    }

    const tokens = await this.cognitoService.signInSocialUser({
      email,
      firstName,
      lastName,
    });
